// src/pages/ProfilePage.js
import React, { useState, useEffect, useCallback } from 'react';
import { useAuth } from '../context/AuthContext';
import { useSensor } from '../hooks/useSensor'; // Changed from useBluetoothSensor
import authService from '../services/authService';
import './ProfilePage.css';

const ProfilePage = () => {
    const { user, logout } = useAuth();
    const { status: sensorStatus } = useSensor(); // Now using the correct hook
    
    const [activeTab, setActiveTab] = useState('profile');
    const [profile, setProfile] = useState({
        username: user?.username || '',
        email: user?.email || '',
        healthRecordId: user?.healthRecordId || ''
    });
    
    const [passwords, setPasswords] = useState({
        current: '',
        new: '',
        confirm: ''
    });
    
    const [loading, setLoading] = useState(false);
    const [message, setMessage] = useState({ type: '', text: '' });
    const [fingerprintStatus, setFingerprintStatus] = useState('not_enrolled');

    // Rest of your ProfilePage component remains the same...
    // ... (keep all existing functions)

    return (
        <div className="profile-page">
            {/* ... existing JSX ... */}
            {activeTab === 'fingerprint' && (
                <div className="fingerprint-settings">
                    <h2>Fingerprint Authentication</h2>
                    
                    <div className="fingerprint-status">
                        <div className={`status-indicator ${fingerprintStatus}`}></div>
                        <div>
                            <h3>Status: {
                                fingerprintStatus === 'enrolled' 
                                    ? '✅ Fingerprint Enrolled' 
                                    : '❌ Not Enrolled'
                            }</h3>
                            <p>
                                {fingerprintStatus === 'enrolled' 
                                    ? 'You can use your fingerprint to log in'
                                    : 'Enroll your fingerprint for faster, more secure login'}
                            </p>
                        </div>
                    </div>

                    {sensorStatus.connected ? (
                        fingerprintStatus === 'enrolled' ? (
                            <button 
                                className="btn btn-secondary"
                                onClick={handleReEnrollFingerprint}
                                disabled={loading}
                            >
                                {loading ? 'Processing...' : 'Re-enroll Fingerprint'}
                            </button>
                        ) : (
                            <button 
                                className="btn btn-primary"
                                onClick={handleEnrollFingerprint}
                                disabled={loading}
                            >
                                {loading ? 'Processing...' : 'Enroll Fingerprint'}
                            </button>
                        )
                    ) : (
                        <div className="sensor-warning">
                            ⚠️ Fingerprint sensor not connected. 
                            Please connect the sensor to enroll fingerprints.
                        </div>
                    )}
                </div>
            )}
        </div>
    );
};

export default ProfilePage;
